chart.options:
chart: {
  type: 'bar',
  height: 350
},
plotOptions: {
  bar: {
    borderRadius: 4,
    borderRadiusApplication: 'end',
    horizontal: true,
  }
},
dataLabels: {
  enabled: false
},
title: {
  text: 'Monthly Visitors by Country',
  align: 'left'
},
xaxis: {
  categories: ['South Korea', 'Canada', 'United Kingdom', 'Netherlands', 'Italy', 'France', 'Japan',
    'United States', 'China', 'Germany'
  ],
  labels: {
    formatter: function (val) {
      return val + 'k'
    }
  }
}
